/**
 * State Management with Zustand
 * Centralized state for the world builder app
 */

import create from 'zustand';
import { AreaAPI, RoomAPI, MobileAPI, ObjectAPI, ValidationAPI } from '../api/client.js';

export const useWorldBuilderStore = create((set, get) => ({
  // State
  areas: [],
  currentArea: null,
  currentAreaData: null,
  selectedRoom: null,
  selectedMobile: null,
  selectedObject: null,
  selectedReset: null,
  loading: false,
  error: null,
  message: null,
  validationResult: null,

  // Actions: Area Management
  loadAreas: async () => {
    set({ loading: true, error: null });
    const result = await AreaAPI.listAreas();
    if (result.success) {
      set({ areas: result.areas, loading: false });
    } else {
      set({ error: result.error, loading: false });
    }
  },

  loadArea: async (areaName) => {
    set({ loading: true, error: null });
    const result = await AreaAPI.loadArea(areaName);
    if (result.success) {
      set({
        currentArea: areaName,
        currentAreaData: result.areaData,
        selectedRoom: null,
        loading: false,
      });
    } else {
      set({ error: result.error, loading: false });
    }
  },

  createArea: async (name, options) => {
    set({ loading: true, error: null });
    const result = await AreaAPI.createArea(name, options);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        loading: false,
        message: result.message,
      });
      // Refresh areas list
      get().loadAreas();
    } else {
      set({ error: result.error, loading: false });
    }
  },

  saveArea: async () => {
    const { currentArea, currentAreaData } = get();
    if (!currentArea || !currentAreaData) return;

    set({ loading: true, error: null });
    const result = await AreaAPI.saveArea(currentArea, currentAreaData);
    if (result.success) {
      set({ loading: false, message: result.message });
    } else {
      set({ error: result.error, loading: false });
    }
  },

  deleteArea: async (areaName) => {
    set({ loading: true, error: null });
    const result = await AreaAPI.deleteArea(areaName);
    if (result.success) {
      set({
        currentArea: null,
        currentAreaData: null,
        selectedRoom: null,
        loading: false,
        message: result.message,
      });
      get().loadAreas();
    } else {
      set({ error: result.error, loading: false });
    }
  },

  // Actions: Room Management
  createRoom: async (room) => {
    const { currentAreaData } = get();
    if (!currentAreaData) return;

    const result = await RoomAPI.createRoom(currentAreaData, room);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        selectedRoom: result.room.vnum,
        message: result.message,
      });
    } else {
      set({ error: result.error });
    }
  },

  selectRoom: (vnum) => {
    const { currentAreaData } = get();
    if (!currentAreaData) return;
    const room = currentAreaData.rooms.find(r => r.vnum === vnum);
    set({ selectedRoom: vnum });
  },

  updateRoom: async (vnum, roomData) => {
    const { currentAreaData } = get();
    if (!currentAreaData) return;

    const result = await RoomAPI.updateRoom(vnum, currentAreaData, roomData);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        message: result.message,
      });
    } else {
      set({ error: result.error });
    }
  },

  deleteRoom: async (vnum) => {
    const { currentAreaData } = get();
    if (!currentAreaData) return;

    const result = await RoomAPI.deleteRoom(vnum, currentAreaData);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        selectedRoom: null,
        message: result.message,
      });
    } else {
      set({ error: result.error });
    }
  },

  addExit: async (vnum, exit) => {
    const { currentAreaData } = get();
    if (!currentAreaData) return;

    const result = await RoomAPI.addExit(vnum, currentAreaData, exit);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        message: result.message,
      });
    } else {
      set({ error: result.error });
    }
  },

  removeExit: async (vnum, direction, options = {}) => {
    const { currentAreaData } = get();
    if (!currentAreaData) return;

    const result = await RoomAPI.removeExit(vnum, direction, currentAreaData, options);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        message: result.message,
      });
    } else {
      set({ error: result.error });
    }
  },

  updateExit: async (vnum, direction, exitData) => {
    const { currentAreaData } = get();
    if (!currentAreaData) return;

    const result = await RoomAPI.updateExit(vnum, direction, currentAreaData, exitData);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        message: result.message,
      });
    } else {
      set({ error: result.error });
    }
  },

  // Actions: Mobile Management
  createMobile: async (mobile) => {
    const { currentArea, currentAreaData } = get();
    if (!currentArea || !currentAreaData) return;

    const result = await MobileAPI.createMobile(currentArea, currentAreaData, mobile);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        selectedMobile: result.mobile.vnum,
        message: result.message,
      });
    } else {
      set({ error: result.error });
    }
  },

  selectMobile: (vnum) => {
    set({ selectedMobile: vnum });
  },

  updateMobile: async (vnum, mobile) => {
    const { currentArea, currentAreaData } = get();
    if (!currentArea || !currentAreaData) return;

    const result = await MobileAPI.updateMobile(currentArea, vnum, currentAreaData, mobile);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        message: result.message,
      });
    } else {
      set({ error: result.error });
    }
  },

  deleteMobile: async (vnum, options = {}) => {
    const { currentArea, currentAreaData } = get();
    if (!currentArea || !currentAreaData) return;

    const result = await MobileAPI.deleteMobile(currentArea, vnum, currentAreaData, options);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        selectedMobile: null,
        message: result.message,
      });
    } else {
      set({ error: result.error });
    }
  },

  // Actions: Object Management
  createObject: async (object) => {
    const { currentArea, currentAreaData } = get();
    if (!currentArea || !currentAreaData) return;

    const result = await ObjectAPI.createObject(currentArea, currentAreaData, object);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        selectedObject: result.object.vnum,
        message: result.message,
      });
    } else {
      set({ error: result.error });
    }
  },

  selectObject: (vnum) => {
    set({ selectedObject: vnum });
  },

  updateObject: async (vnum, object) => {
    const { currentArea, currentAreaData } = get();
    if (!currentArea || !currentAreaData) return;

    const result = await ObjectAPI.updateObject(currentArea, vnum, currentAreaData, object);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        message: result.message,
      });
    } else {
      set({ error: result.error });
    }
  },

  deleteObject: async (vnum, options = {}) => {
    const { currentArea, currentAreaData } = get();
    if (!currentArea || !currentAreaData) return;

    const result = await ObjectAPI.deleteObject(currentArea, vnum, currentAreaData, options);
    if (result.success) {
      set({
        currentAreaData: result.areaData,
        selectedObject: null,
        message: result.message,
      });
    } else {
      set({ error: result.error });
    }
  },

  // Actions: Validation
  validateArea: async () => {
    const { currentArea, currentAreaData } = get();
    if (!currentArea || !currentAreaData) return;

    const result = await ValidationAPI.validate(currentArea, currentAreaData);
    if (result.success !== false) {
      set({ validationResult: result });
    } else {
      set({ error: result.error });
    }
  },

  getReferencesFor: async (vnum) => {
    const { currentArea, currentAreaData } = get();
    if (!currentArea || !currentAreaData) return null;

    const result = await ValidationAPI.getReferences(currentArea, vnum, currentAreaData);
    return result;
  },

  // Utility Actions
  clearError: () => set({ error: null }),
  clearMessage: () => set({ message: null }),
}));

export default useWorldBuilderStore;
